# INTERPRETATION 1: {key: pinyin} for both
def build_interp1():
    sm_k2p = dict(sm)  # key -> pinyin
    ym_k2p = {}
    for k, v in ym.items():
        if isinstance(v, list):
            for vv in v:
                ym_k2p[vv] = k
        else:
            ym_k2p[v] = k
    return sm_k2p, ym_k2p

# INTERPRETATION 2: {pinyin: key} for sm, {pinyin: key} for ym  
def build_interp2():
    sm_p2k = dict(sm)  # pinyin -> key
    ym_p2k = dict(ym)  # pinyin -> key
    sm_k2p = {v: k for k, v in sm_p2k.items()}  # key -> pinyin
    ym_k2p = {}
    for pinyin, key in ym_p2k.items():
        if isinstance(key, list):
            for k in key:
                ym_k2p[k] = pinyin
        else:
            ym_k2p[key] = pinyin
    return sm_k2p, ym_k2p

